import { useEffect, useRef, useState } from "react";
import { lerp, clamp, ease } from "./helpers";

export default function Focus() {
  const [progress, setProgress] = useState(0);
  const sectionRef = useRef(null);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current; if (!el) return;
      const rect = el.getBoundingClientRect();
      const p = clamp(-rect.top / (el.offsetHeight - window.innerHeight), 0, 1);
      setProgress(p);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const titleP = ease(clamp(progress / 0.25, 0, 1));

  const people = [
    { label: "Truck drivers",      riskRate: "4.75%", meanAge: "30.90", img: "/assets/truck-driver.png" },
    { label: "Dark Store Workers",  riskRate: "2.36%", meanAge: "24.34", img: "/assets/store.png" },
    { label: "Delivery Partners",   riskRate: "3.04%", meanAge: "27.94", img: "/assets/delivery.png" },
  ];

  return (
    <div ref={sectionRef} style={{ height: "250vh", position: "relative" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh", overflow: "hidden",
        background: `radial-gradient(ellipse 70% 80% at 100% 50%, rgba(28,67,185,0.55) 0%, transparent 65%), #0d0d0d`,
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        padding: "80px 64px",
      }}>
        {/* Title */}
        <h2 style={{
          fontFamily: "'Inter','Helvetica Neue',sans-serif",
          fontSize: "clamp(52px,7.5vw,110px)",
          fontWeight: 800, color: "white",
          margin: "0 0 48px", textAlign: "center", lineHeight: 1.05,
          opacity: titleP, transform: `translateY(${lerp(30, 0, titleP)}px)`,
        }}>
          People in focus
        </h2>

        {/* Cards */}
        <div style={{
          display: "grid", gridTemplateColumns: "repeat(3,1fr)",
          gap: 20, width: "100%", maxWidth: 1100,
        }}>
          {people.map((p, i) => {
            const cardP = ease(clamp((progress - 0.15 - i * 0.08) / 0.30, 0, 1));
            return (
              <div key={i} style={{
                background: "rgba(255,255,255,0.06)",
                border: "1px solid rgba(255,255,255,0.1)",
                borderRadius: 16,
                padding: "32px 28px 0",
                display: "flex", flexDirection: "column",
                position: "relative", overflow: "hidden",
                minHeight: 380,
                opacity: cardP,
                transform: `translateY(${lerp(40, 0, cardP)}px)`,
              }}>
                {/* Label */}
                <div style={{
                  color: "#e53e3e", fontSize: "clamp(14px,1.1vw,18px)",
                  fontWeight: 700, marginBottom: 24,
                  fontFamily: "'Inter',sans-serif",
                }}>{p.label}</div>

                {/* Risk Rate */}
                <div style={{
                  color: "white", fontSize: "clamp(32px,3.5vw,52px)",
                  fontWeight: 800, lineHeight: 1, fontFamily: "'Inter',sans-serif",
                }}>{p.riskRate}</div>
                <div style={{
                  color: "rgba(255,255,255,0.6)", fontSize: 15,
                  marginTop: 6, marginBottom: 28, fontFamily: "'Inter',sans-serif",
                }}>Risk Rate</div>

                {/* Mean Age */}
                <div style={{
                  color: "rgba(255,255,255,0.6)", fontSize: 15,
                  marginBottom: 6, fontFamily: "'Inter',sans-serif",
                }}>Mean Age</div>
                <div style={{
                  color: "white", fontSize: "clamp(28px,3vw,46px)",
                  fontWeight: 800, lineHeight: 1, fontFamily: "'Inter',sans-serif",
                }}>{p.meanAge}</div>
                <div style={{
                  color: "rgba(255,255,255,0.6)", fontSize: 15,
                  marginTop: 6, fontFamily: "'Inter',sans-serif",
                }}>years</div>

                {/* Image — diagonal bottom-right, rotated slightly */}
                <img
                  src={p.img}
                  alt={p.label}
                  style={{
                    position: "absolute",
                    bottom: -18,
                    right: -18,
                    width: "52%",
                    maxWidth: 185,
                    objectFit: "contain",
                    objectPosition: "bottom right",
                    transform: "rotate(12deg)",
                    transformOrigin: "bottom right",
                    opacity: 0.92,
                  }}
                />
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
